if not chunk_hashes:
    tree_hash_hex = hashlib.sha256(b"").hexdigest()
else:
    while len(chunk_hashes) > 1:
        next_level = []
        for i in range(0, len(chunk_hashes), 2):
            left = chunk_hashes[i]
            if i + 1 < len(chunk_hashes):
                right = chunk_hashes[i + 1]
                next_level.append(hashlib.sha256(left + right).digest())
            else:
                next_level.append(left)
        chunk_hashes = next_level

    tree_hash_hex = chunk_hashes[0].hex()

return linear_hash, tree_hash_hex

