def _get_from_source(source, key):
    if source is None:
        return default_sentinel

    if isinstance(source, dict):
        if key in source:
            return source[key]
        prefixed_key = f"pyinfra_{key}"
        if prefixed_key in source:
            return source[prefixed_key]
    else:
        if hasattr(source, key):
