def _gen():
    buf = b""
    for chunk in chunks:
        if chunk == b"":
            if buf:
                yield buf
                buf = b""
            continue

        buf += chunk
        while True:
            nl = buf.find(b"\n")
            if nl == -1:
                break
            yield buf[:nl]
            buf = buf[nl + 1 :]

    if buf:
        yield buf

return _gen()

