    X = X.reshape(-1, 1)

mu = np.asarray(mu, dtype=float)
var = np.asarray(var, dtype=float)

if n_noisy is None:
    n_new = X.shape[0]
else:
    n_new = n_noisy

if n_new == 0:
    return mu, var

new_mu = np.mean(X, axis=0)
new_var = np.var(X, axis=0)

n_total = n_past + n_new
if n_total == 0:
    return mu, var

total_mu = (n_past * mu + n_new * new_mu) / n_total

# Chan et al. online variance update
total_var = (
    n_past * (var + (mu - total_mu) ** 2)
    + n_new * (new_var + (new_mu - total_mu) ** 2)
) / n_total

return total_mu, total_var

