# Build a lookup of recipe -> its dependency options.
# We only expand "alternative" dependencies here; plain dependencies are
# appended to every combination.
recipe_map = {r.name(): r for r in ctx.recipe_build_order}

def _expand_one(combo):
    # Start with the current combination.
    combos = [list(combo)]

    # Add non-alternative dependencies for every recipe in the combo.
    for recipe_name in list(combo):
        recipe = recipe_map.get(recipe_name)
        if not recipe:
            continue
        for dep in getattr(recipe, "depends", []):
            if dep not in combo:
                for c in combos:
                    if dep not in c:
                        c.append(dep)

    # Expand alternative dependencies if the recipe declares them.
    # We treat any dependency entry containing "|" or "||" as alternatives.
    expanded = []
    for c in combos:
        alt_groups = []
        for recipe_name in c:
            recipe = recipe_map.get(recipe_name)
            if not recipe:
                continue
            for dep in getattr(recipe, "depends", []):
                if isinstance(dep, (list, tuple, set)):
                    alt_groups.append(list(dep))
                elif isinstance(dep, str) and ("|" in dep):
                    parts = [p.strip() for p in dep.split("|") if p.strip()]
                    if len(parts) > 1:
                        alt_groups.append(parts)

        if not alt_groups:
            expanded.append(c)
            continue

        # Cartesian product over alternative groups.
        combos_to_expand = [c]
        for group in alt_groups:
            new_combos = []
            for base in combos_to_expand:
                for choice in group:
                    nc = list(base)
                    # Remove any textual alternative markers if present.
                    for other in group:
                        if other in nc and other != choice:
                            nc.remove(other)
                    if choice not in nc:
                        nc.append(choice)
                    new_combos.append(nc)
            combos_to_expand = new_combos
        expanded.extend(combos_to_expand)

    return expanded

# Expand each recipe list independently and flatten unique results.
result = []
seen = set()

for combo in recipes:
    for expanded_combo in _expand_one(combo):
        # Preserve order while deduplicating.
        key = tuple(expanded_combo)
        if key not in seen:
            seen.add(key)
            result.append(expanded_combo)

return result

